export function script(input) {
  const asList = (value) => Array.isArray(value) ? value : (typeof value === 'string' && value.trim() ? value.split(/[\n,]+/) : []);
  const seeds = asList(input.seedUrls).map(String).map((value) => value.trim()).filter(Boolean);
  const crawlEndpoints = asList(input.crawlEndpoints).map(String).map((value) => value.trim()).filter(Boolean);
  const knownApiPaths = asList(input.knownApiPaths).map(String).map((value) => value.trim()).filter(Boolean);
  const intensity = String(input.scanIntensity || 'safe').toLowerCase();
  const safePaths = ['/api', '/api/', '/api-docs', '/api/docs', '/docs', '/swagger', '/swagger/', '/swagger-ui/', '/swagger.json', '/swagger/v1/swagger.json', '/openapi.json', '/openapi.yaml', '/redoc', '/graphql', '/graphiql', '/playground', '/admin', '/actuator', '/actuator/health', '/metrics', '/debug'];
  const thoroughPaths = ['/v1', '/v2', '/v3', '/rest', '/rest/products/search', '/api/v1', '/api/v2', '/api/swagger.json', '/api/openapi.json', '/swagger-resources', '/swagger-resources/configuration/ui', '/_debug_toolbar/', '/console', '/explorer', '/api/explorer'];
  const interestingPath = /(api|graphql|graphiql|swagger|openapi|redoc|docs|admin|actuator|metrics|debug|explorer|playground)/i;
  const candidates = new Map();
  const counters = { generatedFromSeeds: 0, generatedFromCrawl: 0, generatedFromKnownPaths: 0 };
  function add(url, source) {
    if (!url || candidates.size >= (intensity === 'thorough' ? 240 : 140)) return;
    try {
      const parsed = new URL(url);
      if (!['http:', 'https:'].includes(parsed.protocol)) return;
      parsed.hash = '';
      const normalized = parsed.toString();
      if (!candidates.has(normalized)) {
        candidates.set(normalized, { url: normalized, source });
        if (source === 'seed') counters.generatedFromSeeds += 1;
        if (source === 'crawl') counters.generatedFromCrawl += 1;
        if (source === 'known') counters.generatedFromKnownPaths += 1;
      }
    } catch {}
  }
  function addPath(seed, path, source) {
    try {
      const base = new URL(seed);
      const normalizedPath = String(path || '').startsWith('/') ? String(path) : '/' + String(path || '');
      add(base.origin + normalizedPath, source);
    } catch {}
  }
  for (const seed of seeds) {
    add(seed, 'seed');
    for (const path of safePaths) addPath(seed, path, 'seed');
    if (intensity === 'thorough') for (const path of thoroughPaths) addPath(seed, path, 'seed');
    for (const path of knownApiPaths) addPath(seed, path, 'known');
  }
  for (const endpoint of crawlEndpoints) {
    if (interestingPath.test(endpoint)) add(endpoint, 'crawl');
  }
  const candidateUrls = Array.from(candidates.keys());
  return { candidateUrls, candidateSummary: { candidateCount: candidateUrls.length, seedCount: seeds.length, crawlEndpointCount: crawlEndpoints.length, knownApiPathCount: knownApiPaths.length, scanIntensity: intensity, ...counters } };
}

export function script(input) {
  const list = (value) => Array.isArray(value) ? value : [];
  const severityRank = { critical: 5, high: 4, medium: 3, low: 2, info: 1, unknown: 0 };
  const normalizeSeverity = (value) => String(value || 'unknown').toLowerCase();
  const rank = (value) => severityRank[normalizeSeverity(value)] || 0;
  const candidateSummary = input.candidateSummary && typeof input.candidateSummary === 'object' ? input.candidateSummary : {};
  const httpResponses = list(input.httpResponses);
  const nucleiFindings = list(input.nucleiFindings);
  function responseUrl(item) { return item?.url || item?.finalUrl || item?.input || item?.host || ''; }
  function responseText(item) { return [responseUrl(item), item?.title, item?.webserver, ...(Array.isArray(item?.technologies) ? item.technologies : [])].join(' '); }
  function classifyResponse(item) {
    const status = Number(item?.statusCode ?? item?.status ?? 0);
    if (!(status >= 200 && status < 400)) return null;
    const text = responseText(item);
    const url = responseUrl(item);
    if (/graphql|graphiql|playground/i.test(text)) return { category: 'graphql', severity: 'high', title: 'Potential exposed GraphQL surface', url, evidence: { statusCode: status, title: item?.title || null, technologies: item?.technologies || [] } };
    if (/swagger|openapi|redoc|api-docs|api docs|swagger ui/i.test(text)) return { category: 'api-docs', severity: 'medium', title: 'Potential exposed API documentation', url, evidence: { statusCode: status, title: item?.title || null, technologies: item?.technologies || [] } };
    if (/actuator|metrics|debug|admin|console|explorer/i.test(text)) return { category: 'debug-admin', severity: 'medium', title: 'Potential exposed API admin or debug surface', url, evidence: { statusCode: status, title: item?.title || null, technologies: item?.technologies || [] } };
    return null;
  }
  const httpFindings = httpResponses.map(classifyResponse).filter(Boolean).map((item) => ({ source: 'httpx', severity: item.severity, title: item.title, url: item.url, category: item.category, evidence: item.evidence }));
  function nucleiCategory(finding) {
    const tags = Array.isArray(finding?.tags) ? finding.tags.map(String).join(' ') : '';
    const text = [finding?.templateId, finding?.name, finding?.matchedAt, finding?.host, finding?.url, tags].join(' ');
    if (/graphql|graphiql|playground/i.test(text)) return 'graphql';
    if (/swagger|openapi|redoc|api-docs|api docs|swagger ui/i.test(text)) return 'api-docs';
    if (/actuator|metrics|debug|admin|console|explorer/i.test(text)) return 'debug-admin';
    return null;
  }
  const nuclei = nucleiFindings.map((finding) => ({ source: 'nuclei', severity: normalizeSeverity(finding?.severity), title: finding?.name || finding?.templateId || 'Nuclei API exposure finding', url: finding?.matchedAt || finding?.host || finding?.url || '', templateId: finding?.templateId || null, tags: Array.isArray(finding?.tags) ? finding.tags : [], category: nucleiCategory(finding), raw: finding }));
  const priorityFindings = [...nuclei, ...httpFindings].sort((a, b) => rank(b.severity) - rank(a.severity) || (a.source === 'nuclei' ? -1 : b.source === 'nuclei' ? 1 : String(a.url).localeCompare(String(b.url))));
  const countsBySource = priorityFindings.reduce((acc, item) => { acc[item.source] = (acc[item.source] || 0) + 1; return acc; }, {});
  const countsBySeverity = priorityFindings.reduce((acc, item) => { acc[item.severity] = (acc[item.severity] || 0) + 1; return acc; }, {});
  return { report: { summary: { seedUrls: list(input.seedUrls).length, candidatesGenerated: Number(candidateSummary.candidateCount || list(input.candidateUrls).length), candidatesResponsive: httpResponses.length, findings: priorityFindings.length, nucleiFindings: nucleiFindings.length, graphqlSignals: priorityFindings.filter((item) => item.category === 'graphql').length, apiDocSignals: priorityFindings.filter((item) => item.category === 'api-docs').length, highestSeverity: priorityFindings[0]?.severity || null, countsBySource, countsBySeverity }, authorizationNotes: input.authorizationNotes || null, candidateSummary, candidates: list(input.candidateUrls).slice(0, 200), httpEvidence: httpResponses.slice(0, 200), nucleiFindings: nucleiFindings.slice(0, 100), priorityFindings: priorityFindings.slice(0, 100), nextSteps: ['Manually validate every exposed API surface against program scope', 'Confirm whether documentation or GraphQL access leaks sensitive schema, auth, or environment details', 'Avoid destructive GraphQL or API mutations during validation', 'Respect published rate limits and authentication requirements'] } };
}
